mapper.select:
SELECT id, userNm, eml, mtelno, gndrSe, userSe, userStsSe FROM ( SELECT USER_ID AS id , USER_NM AS userNm , EML AS eml , MTELNO AS mtelno , GNDR_SE AS gndrSe , 'A' AS userSe , ADM_STS_SE AS userStsSe FROM CMS_USER_ADMIN UNION ALL SELECT USER_ID AS id , USER_NM AS userNm , EML AS eml , MTELNO AS mtelno , GNDR_SE AS gndrSe , 'E' AS userSe , USER_STS_SE AS userStsSe FROM CMS_USER_TASK UNION ALL SELECT USER_ID AS id , USER_NM AS userNm , EML AS eml , MTELNO AS mtelno , GNDR_SE AS gndrSe , 'G' AS userSe , USER_STS_SE AS userStsSe FROM CMS_USER )
AND userSe = #{userSe}
ORDER BY userSe, userNm OFFSET #{offset} ROWS FETCH NEXT #{size} ROWS ONLY

mapper.insert:
INSERT INTO CMS_USER (
    USER_ID
  , USER_NM
  , MTELNO
  , TELNO
  , GNDR_SE
  , EML
  , ADDR
  , DADDR
  , ZIP
  , USER_STS_SE
  , EML_CERT_YN
  , TELNO_CERT_YN
  , CRT_AT
  , CRT_BY
  , CRT_IP
  , CRT_PGM
  , UPD_AT
  , UPD_BY
  , UPD_IP
  , UPD_PGM
) VALUES (
    #{userId}
  , #{userNm}
  , #{mtelno}
  , #{telno}
  , #{gndrSe}
  , #{eml}
  , #{addr}
  , #{daddr}
  , #{zip}
  , #{userStsSe}
  , #{emlCertYn}
  , #{telnoCertYn}
  , SYSDATE
  , 'SYSTEM'
  , 'SYSTEM'
  , 'ManageService'
  , SYSDATE
  , 'SYSTEM'
  , 'SYSTEM'
  , 'ManageService'
)

mapper.update:
UPDATE CMS_USER_ADMIN
   SET USER_NM  = #{vo.userNm}
     , EML      = #{vo.eml}
     , MTELNO   = #{vo.mtelno}
     , GNDR_SE  = #{vo.gndrSe}
     , TELNO    = #{vo.telno}
     , ADDR     = #{vo.addr}
     , DADDR    = #{vo.daddr}
     , UPD_AT   = SYSDATE
     , UPD_BY   = 'SYSTEM'
     , UPD_IP   = 'SYSTEM'
     , UPD_PGM  = 'ManageService'
 WHERE USER_ID  = #{id}

UPDATE CMS_USER_TASK
   SET USER_NM  = #{vo.userNm}
     , EML      = #{vo.eml}
     , MTELNO   = #{vo.mtelno}
     , GNDR_SE  = #{vo.gndrSe}
     , TELNO    = #{vo.telno}
     , ADDR     = #{vo.addr}
     , DADDR    = #{vo.daddr}
     , UPD_AT   = SYSDATE
     , UPD_BY   = 'SYSTEM'
     , UPD_IP   = 'SYSTEM'
     , UPD_PGM  = 'ManageService'
 WHERE USER_ID  = #{id}

UPDATE CMS_USER
   SET USER_NM  = #{vo.userNm}
     , EML      = #{vo.eml}
     , MTELNO   = #{vo.mtelno}
     , GNDR_SE  = #{vo.gndrSe}
     , TELNO    = #{vo.telno}
     , ADDR     = #{vo.addr}
     , DADDR    = #{vo.daddr}
     , ZIP      = #{vo.zip}
     , UPD_AT   = SYSDATE
     , UPD_BY   = 'SYSTEM'
     , UPD_IP   = 'SYSTEM'
     , UPD_PGM  = 'ManageService'
 WHERE USER_ID  = #{id}

UPDATE CMS_PWD
   SET PWD     = #{pwd}
     , UPD_AT  = SYSDATE
     , UPD_BY  = 'SYSTEM'
     , UPD_IP  = 'SYSTEM'
     , UPD_PGM = 'ManageService'
 WHERE USER_ID = #{userId}
   AND USER_SE = #{userSe}

mapper.delete:
DELETE FROM CMS_PWD
 WHERE USER_ID = #{userId}
   AND USER_SE = #{userSe}
